  doc.setFont('helvetica', 'normal');
  doc.setFontSize(9);
  doc.setTextColor(200, 200, 200);
  doc.text(`Invoice: ${order.invoice_number || order.invoiceNumber || 'N/A'}`, 210 - 20, 26, { align: 'right' });
  doc.text(`Order: ${order.order_id || order.orderId}`, 210 - 20, 32, { align: 'right' });
  doc.text(`Date: ${new Date(order.created_at || order.date || Date.now()).toLocaleDateString('en-IN')}`, 210 - 20, 38, { align: 'right' });

  // ── Bill To section ──
