  // ── Shop info (right side) ──
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(10);
  doc.setTextColor(...gold);
  doc.text('FROM', 120, 66);
  doc.setFillColor(...gold);
  doc.rect(120, 67, 18, 0.5, 'F');

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(11);
  doc.setTextColor(...black);
  doc.text('Vakif Jewellery', 120, 75);
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(9);
  doc.setTextColor(...grey);
  doc.text('Supur, Idar, Gujarat — 383430', 120, 81);
  doc.text('+91 98989 37895', 120, 87);
  doc.text('vakif@gmail.com', 120, 93);

  // ── Status badge ──
  const status = (order.status || 'pending').toUpperCase();
  const statusColor = {
    DELIVERED: [34, 197, 94],
    PENDING:   [234, 179, 8],
    CANCELLED: [239, 68, 68],
    CONFIRMED: [59, 130, 246],
    SHIPPED:   [168, 85, 247],
    PROCESSING:[249, 115, 22],
  }[status] || [150, 150, 150];

