  doc.setTextColor(...gold);
  doc.text('Thank you for shopping at Vakif Jewellery!', 105, footerY + 6, { align: 'center' });
  doc.setTextColor(160, 160, 160);
  doc.text('Supur, Idar, Gujarat | +91 98989 37895 | vakif@gmail.com | wa.me/919898937895', 105, footerY + 12, { align: 'center' });

  // ── Watermark (subtle) ──
  doc.setGState(new doc.GState({ opacity: 0.04 }));
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(80);
  doc.setTextColor(...gold);
  doc.text('VAKIF', 105, 160, { align: 'center', angle: 45 });
  doc.setGState(new doc.GState({ opacity: 1 }));

  const filename = `Vakif_Invoice_${order.invoice_number || order.order_id || 'order'}.pdf`;
  doc.save(filename);
}
